import os
import sys
import subprocess
from pathlib import Path

ROOT = Path(__file__).resolve().parent
REQUIREMENTS = ROOT / "requirements.txt"


def run(cmd):
    print(f"+ {' '.join(cmd)}", flush=True)
    subprocess.run(cmd, check=True, cwd=ROOT)


def main():
    python = sys.executable or "python"

    if REQUIREMENTS.exists():
        run([python, "-m", "pip", "install", "--upgrade", "pip"])
        run([python, "-m", "pip", "install", "-r", str(REQUIREMENTS)])
    else:
        print("requirements.txt not found; skipping dependency installation.", flush=True)

    test_commands = [
        [python, "-m", "pytest", "-q"],
        [python, "-m", "unittest", "discover", "-v"],
    ]

    tests_run = False
    last_error = None
    for cmd in test_commands:
        try:
            run(cmd)
            tests_run = True
            break
        except subprocess.CalledProcessError as e:
            last_error = e

    if not tests_run:
        raise last_error or RuntimeError("No test runner succeeded.")

    dist_dir = ROOT / "dist"
    dist_dir.mkdir(exist_ok=True)

    if (ROOT / "pyproject.toml").exists() or (ROOT / "setup.py").exists() or (ROOT / "setup.cfg").exists():
        run([python, "-m", "build"])
    else:
        archive_name = dist_dir / "deployment_package"
        run([python, "-m", "shutil", "make_archive", str(archive_name), "zip", str(ROOT)])

    print("Deployment workflow completed successfully.", flush=True)


if __name__ == "__main__":
    main()